import {
  Button,
  Callout,
  Card,
  CardBody,
  CardHeader,
  Divider,
  Grid,
  H1,
  H2,
  Row,
  Select,
  Spacer,
  Stack,
  Stat,
  Text,
  TextInput,
  useCanvasState,
  useHostTheme,
} from "cursor/canvas";

const MONTHS: { value: string; label: string }[] = [
  { value: "1", label: "January" },
  { value: "2", label: "February" },
  { value: "3", label: "March" },
  { value: "4", label: "April" },
  { value: "5", label: "May" },
  { value: "6", label: "June" },
  { value: "7", label: "July" },
  { value: "8", label: "August" },
  { value: "9", label: "September" },
  { value: "10", label: "October" },
  { value: "11", label: "November" },
  { value: "12", label: "December" },
];

function countSaturdaysInMonth(month: number, year: number): number {
  const daysInMonth = new Date(year, month, 0).getDate();
  let count = 0;
  for (let day = 1; day <= daysInMonth; day++) {
    if (new Date(year, month - 1, day).getDay() === 6) count++;
  }
  return count;
}

function getSaturdayDates(month: number, year: number): string[] {
  const daysInMonth = new Date(year, month, 0).getDate();
  const dates: string[] = [];
  for (let day = 1; day <= daysInMonth; day++) {
    if (new Date(year, month - 1, day).getDay() === 6) {
      dates.push(
        new Date(year, month - 1, day).toLocaleDateString("en-GB", {
          day: "2-digit",
          month: "short",
        })
      );
    }
  }
  return dates;
}

function fmt(amount: number): string {
  return `₪${amount.toLocaleString("he-IL", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  })}`;
}

export default function ShabbatSalaryCalculator() {
  const theme = useHostTheme();

  const [month, setMonth] = useCanvasState("month", "5");
  const [year, setYear] = useCanvasState("year", "2026");
  const [baseSalary, setBaseSalary] = useCanvasState("baseSalary", "");
  const [pocketMoney, setPocketMoney] = useCanvasState("pocketMoney", "");
  const [shabbatRate, setShabbatRate] = useCanvasState("shabbatRate", "");
  const [calculated, setCalculated] = useCanvasState("calculated", false);

  const monthNum = parseInt(month) || 1;
  const yearNum = parseInt(year) || new Date().getFullYear();
  const baseSalaryNum = parseFloat(baseSalary) || 0;
  const pocketMoneyNum = parseFloat(pocketMoney) || 0;
  const shabbatRateNum = parseFloat(shabbatRate) || 0;

  const shabbatCount = calculated ? countSaturdaysInMonth(monthNum, yearNum) : 0;
  const shabbatDates = calculated ? getSaturdayDates(monthNum, yearNum) : [];
  const shabbatTotal = shabbatCount * shabbatRateNum;
  const totalSalary = baseSalaryNum + pocketMoneyNum + shabbatTotal;

  const monthName = MONTHS.find((m) => m.value === month)?.label ?? "";
  const isValid =
    baseSalary.trim() !== "" &&
    yearNum >= 1900 &&
    yearNum <= 2200 &&
    monthNum >= 1 &&
    monthNum <= 12;

  return (
    <>
      <style>{`
        @media print {
          .no-print { display: none !important; }
          .print-only { display: block !important; }
        }
        .print-only { display: none; }
      `}</style>

      <Stack gap={24} style={{ padding: 28, maxWidth: 640, margin: "0 auto" }}>
        <Stack gap={4}>
          <H1>Monthly Salary Calculator</H1>
          <Text tone="secondary">
            Calculates Shabbat (Saturday) free-day payments for the selected month.
          </Text>
        </Stack>

        <Divider />

        {/* ── Input form ── */}
        <div className="no-print">
          <Stack gap={16}>
            <H2>Input Details</H2>

            <Grid columns={2} gap={16}>
              <Stack gap={6}>
                <Text size="small" weight="medium">
                  Month
                </Text>
                <Select
                  value={month}
                  onChange={(v) => {
                    setMonth(v);
                    setCalculated(false);
                  }}
                  options={MONTHS}
                />
              </Stack>
              <Stack gap={6}>
                <Text size="small" weight="medium">
                  Year
                </Text>
                <TextInput
                  value={year}
                  onChange={(v) => {
                    setYear(v);
                    setCalculated(false);
                  }}
                  type="number"
                  placeholder="2026"
                />
              </Stack>
            </Grid>

            <Grid columns={1} gap={14}>
              <Stack gap={6}>
                <Text size="small" weight="medium">
                  Base Salary (₪)
                </Text>
                <TextInput
                  value={baseSalary}
                  onChange={(v) => {
                    setBaseSalary(v);
                    setCalculated(false);
                  }}
                  type="number"
                  placeholder="0.00"
                />
              </Stack>

              <Stack gap={6}>
                <Text size="small" weight="medium">
                  Pocket Money (₪)
                </Text>
                <TextInput
                  value={pocketMoney}
                  onChange={(v) => {
                    setPocketMoney(v);
                    setCalculated(false);
                  }}
                  type="number"
                  placeholder="0.00"
                />
              </Stack>

              <Stack gap={6}>
                <Text size="small" weight="medium">
                  Weekly Free Day Amount per Shabbat (₪)
                </Text>
                <TextInput
                  value={shabbatRate}
                  onChange={(v) => {
                    setShabbatRate(v);
                    setCalculated(false);
                  }}
                  type="number"
                  placeholder="0.00"
                />
              </Stack>
            </Grid>

            {!isValid && baseSalary.trim() !== "" && (
              <Callout tone="warning">
                Please enter a valid year (1900–2200) and base salary to calculate.
              </Callout>
            )}

            <Row gap={10} align="center">
              <Button
                variant="primary"
                onClick={() => isValid && setCalculated(true)}
                disabled={!isValid}
              >
                Calculate
              </Button>
              {calculated && (
                <Button variant="secondary" onClick={() => window.print()}>
                  Print
                </Button>
              )}
            </Row>
          </Stack>
        </div>

        {/* ── Results ── */}
        {calculated && (
          <>
            <Divider />

            {/* Print header shown only in print */}
            <div className="print-only">
              <Stack gap={4}>
                <H2>Salary Statement</H2>
                <Text tone="secondary">
                  {monthName} {yearNum}
                </Text>
              </Stack>
            </div>

            <Stack gap={20}>
              <Row align="center">
                <H2 style={{ margin: 0 }}>
                  Results — {monthName} {yearNum}
                </H2>
              </Row>

              <Grid columns={3} gap={16}>
                <Stat value={String(shabbatCount)} label="Shabbat Days" />
                <Stat value={fmt(shabbatTotal)} label="Shabbat Pay" tone="success" />
                <Stat value={fmt(totalSalary)} label="Total Monthly Salary" tone="success" />
              </Grid>

              <Card>
                <CardHeader>Salary Breakdown</CardHeader>
                <CardBody>
                  <Stack gap={12}>
                    <Row align="center">
                      <Text>Base Salary</Text>
                      <Spacer />
                      <Text weight="medium">{fmt(baseSalaryNum)}</Text>
                    </Row>
                    <Row align="center">
                      <Text>Pocket Money</Text>
                      <Spacer />
                      <Text weight="medium">{fmt(pocketMoneyNum)}</Text>
                    </Row>
                    <Row align="center">
                      <Text>
                        Shabbat Days ({shabbatCount} &times; {fmt(shabbatRateNum)})
                      </Text>
                      <Spacer />
                      <Text weight="medium">{fmt(shabbatTotal)}</Text>
                    </Row>
                    <Divider />
                    <Row align="center">
                      <Text weight="semibold">Total Monthly Salary</Text>
                      <Spacer />
                      <Text
                        weight="semibold"
                        style={{ color: theme.accent.primary, fontSize: 15 }}
                      >
                        {fmt(totalSalary)}
                      </Text>
                    </Row>
                  </Stack>
                </CardBody>
              </Card>

              <Card collapsible defaultOpen={false}>
                <CardHeader trailing={`${shabbatCount} dates`}>
                  Shabbat Dates in {monthName} {yearNum}
                </CardHeader>
                <CardBody>
                  <Row gap={8} wrap>
                    {shabbatDates.map((d) => (
                      <div
                        key={d}
                        style={{
                          padding: "3px 10px",
                          borderRadius: 4,
                          background: theme.fill.secondary,
                          color: theme.text.secondary,
                          fontSize: 12,
                          fontVariantNumeric: "tabular-nums",
                        }}
                      >
                        {d}
                      </div>
                    ))}
                  </Row>
                </CardBody>
              </Card>

              <Text tone="secondary" size="small">
                {shabbatCount} Saturday{shabbatCount !== 1 ? "s" : ""} (Shabbat) found in{" "}
                {monthName} {yearNum}. Rate: {fmt(shabbatRateNum)} per day.
              </Text>
            </Stack>
          </>
        )}
      </Stack>
    </>
  );
}
